 26→    /// <summary>
 27→    /// Kusto-backed Service Tree node lookup.
 28→    /// </summary>
 29→    public sealed class ServiceTreeKustoClient : IServiceTreeNodeLookup
 30→    {
 31→        private readonly ServiceTreeKustoOptions kustoOptions;
 32→        private readonly ServiceTreeClientOptions authOptions;
 33→        private readonly ILogger<ServiceTreeKustoClient> logger;
 34→        private readonly TokenCredential? tokenCredential;
 35→        private readonly string tokenScope;
 36→        private readonly bool isConfigured;
 37→        private readonly int maxBatchSize;
 38→        private readonly int maxConcurrency = 4;
 39→
 40→        /// <summary>
 41→        /// Initializes a new instance of the <see cref="ServiceTreeKustoClient"/> class.
 42→        /// </summary>
 43→        /// <param name="kustoOptions">Kusto options.</param>
 44→        /// <param name="authOptions">Auth options.</param>
 45→        /// <param name="logger">Logger instance.</param>
 46→        /// <param name="credentialFactory">Optional credential factory for cross-tenant support.</param>
 47→        public ServiceTreeKustoClient(
 48→            ServiceTreeKustoOptions kustoOptions,
 49→            ServiceTreeClientOptions authOptions,
 50→            ILogger<ServiceTreeKustoClient> logger,
 51→            ICredentialFactory credentialFactory = null)
 52→        {
 53→            this.kustoOptions = kustoOptions ?? throw new ArgumentNullException(nameof(kustoOptions));
 54→            this.authOptions = authOptions ?? throw new ArgumentNullException(nameof(authOptions));
 55→            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
 56→
 57→            if (string.IsNullOrWhiteSpace(this.kustoOptions.ClusterUri)
 58→                || string.IsNullOrWhiteSpace(this.kustoOptions.Database))
 59→            {
 60→                this.logger.LogWarning("ServiceTreeKustoClient: Kusto cluster or database is not configured.");
 61→                this.isConfigured = false;
 62→                return;
 63→            }
 64→
 65→            this.tokenScope = this.ResolveTokenScope(this.kustoOptions);
 66→            if (string.IsNullOrWhiteSpace(this.tokenScope))
 67→            {
 68→                this.logger.LogWarning("ServiceTreeKustoClient: Token scope is not configured.");
 69→                this.isConfigured = false;
 70→                return;
 71→            }
 72→
 73→            this.tokenCredential = this.ResolveTokenCredential(credentialFactory, this.authOptions);
 74→            if (this.tokenCredential == null)
 75→            {
 76→                this.logger.LogWarning("ServiceTreeKustoClient: No AAD credentials configured for Kusto.");
 77→                this.isConfigured = false;
 78→                return;
 79→            }
 80→
 81→            this.maxBatchSize = this.kustoOptions.MaxBatchSize <= 0 ? 200 : this.kustoOptions.MaxBatchSize;
 82→            this.isConfigured = true;
 83→
 84→            this.logger.LogInformation(
 85→                "ServiceTreeKustoClient: Configured. Cluster={Cluster}, Database={Database}, Table={Table}, CredentialType={CredentialType}, TokenScope={TokenScope}.",
 86→                this.kustoOptions.ClusterUri,
 87→                this.kustoOptions.Database,
 88→                this.kustoOptions.HierarchyTableName,
 89→                this.tokenCredential.GetType().Name,
 90→                this.tokenScope);
 91→        }
 92→
 93→        /// <inheritdoc/>
 94→        public async Task<IReadOnlyDictionary<string, ServiceTreeNode>> GetHierarchyNodesByServiceIdsAsync(
 95→            IEnumerable<string> serviceIds,
 96→            CancellationToken cancellationToken)
 97→        {
 98→            var results = new ConcurrentDictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
 99→            if (!this.isConfigured)
100→            {
101→                return results;
102→            }
103→
104→            var uniqueIds = (serviceIds ?? Enumerable.Empty<string>())
105→                .Where(id => !string.IsNullOrWhiteSpace(id))
106→                .Select(id => id.Trim())
107→                .Distinct(StringComparer.OrdinalIgnoreCase)
108→                .ToList();
109→
110→            if (uniqueIds.Count == 0)
111→            {
112→                return results;
113→            }
114→
115→            var batches = this.SplitStringBatches(uniqueIds, this.maxBatchSize);
116→            using var semaphore = new SemaphoreSlim(this.maxConcurrency);
117→            var tasks = batches.Select(async batch =>
118→            {
119→                await semaphore.WaitAsync(cancellationToken);
120→                try
121→                {
122→                    var batchResults = await this.QueryHierarchyBatchAsync(batch, cancellationToken);
123→                    foreach (var pair in batchResults)
124→                    {
125→                        results[pair.Key] = pair.Value;
126→                    }
127→                }
128→                catch (OperationCanceledException)
129→                {
130→                    throw;
131→                }
132→                catch (Exception ex)
133→                {
134→                    this.logger.LogWarning(
135→                        ex,
136→                        "ServiceTreeKustoClient: Batch of {BatchCount} IDs failed; continuing with remaining batches.",
137→                        batch.Count);
138→                }
139→                finally
140→                {
141→                    semaphore.Release();
142→                }
143→            }).ToList();
144→
145→            await Task.WhenAll(tasks);
146→            return results;
147→        }
148→
149→        private static string EscapeKustoString(string value)
150→        {
151→            return value.Replace("'", "''", StringComparison.Ordinal);
152→        }
153→
154→        private async Task<IReadOnlyDictionary<string, ServiceTreeNode>> QueryHierarchyBatchAsync(
155→            IReadOnlyList<string> batch,
156→            CancellationToken cancellationToken)
157→        {
158→            var results = new Dictionary<string, ServiceTreeNode>(StringComparer.OrdinalIgnoreCase);
159→            if (batch.Count == 0)
160→            {
161→                return results;
162→            }
163→
164→            // Build a fast-lookup set of the (already-lowercased) input IDs so we can
165→            // cross-key results by whichever hierarchy column matched each row.
166→            var batchSet = new HashSet<string>(
167→                batch.Select(id => id.ToLowerInvariant()),
168→                StringComparer.OrdinalIgnoreCase);
169→
170→            var hierarchyTable = this.NormalizeIdentifier(this.kustoOptions.HierarchyTableName);
171→            var builder = new StringBuilder();
172→            builder.AppendLine("let ids = datatable(TargetId:string)[");
173→            builder.Append(string.Join(", ", batch.Select(id => $"'{EscapeKustoString(id.ToLowerInvariant())}'")));
174→            builder.AppendLine("];");
175→            builder.AppendLine($"{hierarchyTable}");
176→            builder.AppendLine("| where tolower(ServiceId) in (ids)");
177→            builder.AppendLine("    or tolower(column_ifexists(\"TeamGroupId\", \"\")) in (ids)");
178→            builder.AppendLine("    or tolower(column_ifexists(\"ServiceGroupId\", \"\")) in (ids)");
179→            builder.AppendLine("    or tolower(column_ifexists(\"OrganizationId\", \"\")) in (ids)");
180→            builder.AppendLine("    or tolower(column_ifexists(\"DivisionId\", \"\")) in (ids)");
181→            builder.AppendLine("| project");
182→            builder.AppendLine("    Id = tostring(ServiceId),");
183→            builder.AppendLine("    Name = tostring(column_ifexists(\"ServiceName\", \"\")),");
184→            builder.AppendLine("    Level = tostring(column_ifexists(\"ServiceLevel\", \"\")),");
185→            builder.AppendLine("    TeamGroupId = tostring(column_ifexists(\"TeamGroupId\", \"\")),");
186→            builder.AppendLine("    TeamGroupName = tostring(column_ifexists(\"TeamGroupName\", \"\")),");
187→            builder.AppendLine("    ServiceGroupId = tostring(column_ifexists(\"ServiceGroupId\", \"\")),");
188→            builder.AppendLine("    ServiceGroupName = tostring(column_ifexists(\"ServiceGroupName\", \"\")),");
189→            builder.AppendLine("    OrganizationId = tostring(column_ifexists(\"OrganizationId\", \"\")),");
190→            builder.AppendLine("    OrganizationName = tostring(column_ifexists(\"OrganizationName\", \"\")),");
191→            builder.AppendLine("    DivisionId = tostring(column_ifexists(\"DivisionId\", \"\")),");
192→            builder.AppendLine("    DivisionName = tostring(column_ifexists(\"DivisionName\", \"\"))");
193→            var query = builder.ToString();
194→
195→            var requestProperties = new ClientRequestProperties();
196→            requestProperties.ClientRequestId = $"CodexSite.ServiceTreeHierarchy.{Guid.NewGuid():N}";
197→
198→            try
199→            {
200→                this.logger.LogInformation(
201→                    "ServiceTreeKustoClient: Executing hierarchy query for {BatchCount} IDs against {Cluster}/{Database}/{Table}.",
202→                    batch.Count,
203→                    this.kustoOptions.ClusterUri,
204→                    this.kustoOptions.Database,
205→                    this.kustoOptions.HierarchyTableName);
206→
207→                using var provider = this.CreateQueryProvider();
208→                using var reader = await provider.ExecuteQueryAsync(this.kustoOptions.Database, query, requestProperties);
209→
210→                do
211→                {
212→                    var idOrdinal = this.TryGetOrdinal(reader, "Id");
213→                    if (idOrdinal < 0)
214→                    {
215→                        continue;
216→                    }
217→
218→                    var nameOrdinal = this.TryGetOrdinal(reader, "Name");
219→                    var levelOrdinal = this.TryGetOrdinal(reader, "Level");
220→                    var teamGroupIdOrdinal = this.TryGetOrdinal(reader, "TeamGroupId");
221→                    var serviceGroupIdOrdinal = this.TryGetOrdinal(reader, "ServiceGroupId");
222→                    var serviceGroupNameOrdinal = this.TryGetOrdinal(reader, "ServiceGroupName");
223→                    var organizationIdOrdinal = this.TryGetOrdinal(reader, "OrganizationId");
224→                    var organizationNameOrdinal = this.TryGetOrdinal(reader, "OrganizationName");
225→                    var divisionIdOrdinal = this.TryGetOrdinal(reader, "DivisionId");
226→                    var divisionNameOrdinal = this.TryGetOrdinal(reader, "DivisionName");
227→
228→                    while (reader.Read())
229→                    {
230→                        var id = this.ReadString(reader, idOrdinal);
231→                        if (string.IsNullOrWhiteSpace(id))
232→                        {
233→                            continue;
234→                        }
235→
236→                        var node = new ServiceTreeNode
237→                        {
238→                            Id = id,
239→                            Name = this.ReadString(reader, nameOrdinal),
240→                            Level = this.ReadString(reader, levelOrdinal),
241→                            ServiceGroupId = this.ReadString(reader, serviceGroupIdOrdinal),
242→                            ServiceGroupName = this.ReadString(reader, serviceGroupNameOrdinal),
243→                            OrganizationId = this.ReadString(reader, organizationIdOrdinal),
244→                            OrganizationName = this.ReadString(reader, organizationNameOrdinal),
245→                            DivisionId = this.ReadString(reader, divisionIdOrdinal),
246→                            DivisionName = this.ReadString(reader, divisionNameOrdinal),
247→                        };
248→
249→                        // Always key by the native ServiceId for backward compatibility.
250→                        results[id] = node;
251→
252→                        // Also key by any hierarchy ancestor ID that the caller asked for.
253→                        // This lets a caller who passed an OrganizationId (or ServiceGroupId etc.)
254→                        // find the result via hierarchyResults.TryGetValue(inputId).
255→                        var teamGroupId = this.ReadString(reader, teamGroupIdOrdinal);
256→                        foreach (var hierarchyId in new[]
257→                        {
258→                            teamGroupId,
259→                            node.ServiceGroupId,
260→                            node.OrganizationId,
261→                            node.DivisionId,
262→                        })
263→                        {
264→                            if (!string.IsNullOrWhiteSpace(hierarchyId)
265→                                && batchSet.Contains(hierarchyId.ToLowerInvariant()))
266→                            {
267→                                results[hierarchyId] = node;
268→                            }
269→                        }
270→                    }
271→                }
272→                while (results.Count == 0 && reader.NextResult());
273→
274→                this.logger.LogInformation(
275→                    "ServiceTreeKustoClient: Hierarchy query completed. Returned {ResultCount} results for {BatchCount} input IDs.",
276→                    results.Count,
277→                    batch.Count);
278→            }
279→            catch (OperationCanceledException)
280→            {
281→                throw;
282→            }
283→            catch (Exception ex)
284→            {
285→                this.logger.LogError(
286→                    ex,
287→                    "ServiceTreeKustoClient: hierarchy query failed. Cluster={Cluster}, Database={Database}, Table={Table}, CredentialType={CredentialType}, BatchCount={BatchCount}.",
288→                    this.kustoOptions.ClusterUri,
289→                    this.kustoOptions.Database,
290→                    this.kustoOptions.HierarchyTableName,
291→                    this.tokenCredential?.GetType().Name ?? "null",
292→                    batch.Count);
293→                throw;
294→            }
295→
296→            return results;
297→        }
298→
299→        private ICslQueryProvider CreateQueryProvider()
300→        {
301→            var kcsb = new KustoConnectionStringBuilder(this.kustoOptions.ClusterUri, this.kustoOptions.Database)
302→                .WithAadAzureTokenCredentialsAuthentication(this.tokenCredential!);
303→            return KustoClientFactory.CreateCslQueryProvider(kcsb);
304→        }
305→
306→        private IEnumerable<IReadOnlyList<string>> SplitStringBatches(IReadOnlyList<string> ids, int batchSize)
307→        {
308→            for (int i = 0; i < ids.Count; i += batchSize)
309→            {
310→                var count = Math.Min(batchSize, ids.Count - i);
311→                var batch = new List<string>(count);
312→                for (int j = 0; j < count; j++)
313→                {
314→                    batch.Add(ids[i + j]);
315→                }
316→
317→                yield return batch;
318→            }
319→        }
320→
321→        private string ResolveTokenScope(ServiceTreeKustoOptions options)
322→        {
323→            if (!string.IsNullOrWhiteSpace(options.TokenScope))
324→            {
325→                return options.TokenScope;
326→            }
327→
328→            if (Uri.TryCreate(options.ClusterUri, UriKind.Absolute, out var uri))
329→            {
330→                return $"{uri.GetLeftPart(UriPartial.Authority)}/.default";
331→            }
332→
333→            return string.Empty;
334→        }
335→
336→        private TokenCredential ResolveTokenCredential(
337→            ICredentialFactory? credentialFactory,
338→            ServiceTreeClientOptions options)
339→        {
340→            // When ICredentialFactory is available, use it for cross-tenant support
341→            // (PME MSI → MSFT tenant token).
342→            if (credentialFactory != null)
343→            {
344→                try
345→                {
346→                    var cred = credentialFactory.CreateTokenCredential(AADTenant.MSFT);
347→                    this.logger.LogInformation(
348→                        "ServiceTreeKustoClient: Using ICredentialFactory for MSFT-tenant credential (type={CredType}).",
349→                        cred.GetType().Name);
350→                    return cred;
351→                }
352→                catch (Exception ex)
353→                {
354→                    this.logger.LogError(
355→                        ex,
356→                        "ServiceTreeKustoClient: ICredentialFactory.CreateTokenCredential failed.");
357→                    throw;
358→                }
359→            }
360→
361→            return new DefaultAzureCredential(new DefaultAzureCredentialOptions
362→            {
363→                ManagedIdentityClientId = string.IsNullOrWhiteSpace(options.ManagedIdentityClientId) ? null : options.ManagedIdentityClientId,
364→            });
365→        }
366→
367→        private string NormalizeIdentifier(string value)
368→        {
369→            if (string.IsNullOrWhiteSpace(value))
370→            {
371→                return value;
372→            }
373→
374→            var trimmed = value.Trim();
375→            return trimmed.All(ch => char.IsLetterOrDigit(ch) || ch == '_' || ch == '.')
376→                ? trimmed
377→                : trimmed.Replace("`", string.Empty, StringComparison.Ordinal);
378→        }
379→
380→        private int TryGetOrdinal(IDataReader reader, string name)
381→        {
382→            try
383→            {
384→                return reader.GetOrdinal(name);
385→            }
386→            catch (IndexOutOfRangeException)
387→            {
388→                return -1;
389→            }
390→        }
391→
392→        private string ReadString(IDataReader reader, int ordinal)
393→        {
394→            if (ordinal < 0 || reader.IsDBNull(ordinal))
395→            {
396→                return string.Empty;
397→            }
398→
399→            var value = reader.GetValue(ordinal);
400→            return value?.ToString() ?? string.Empty;
401→        }
402→    }
403→
404→#pragma warning restore CA1303
405→}
