  5→namespace CodeXCore.ServiceTree
  6→{
  7→    using System;
  8→    using System.Collections.Concurrent;
  9→    using System.Collections.Generic;
 10→    using System.Linq;
 11→    using System.Text;
 12→    using System.Threading;
 13→    using System.Threading.Tasks;
 14→    using Microsoft.Extensions.Logging;
 15→
 16→    /// <summary>
 17→    /// Resolves Service Tree node parent group info using the flattened hierarchy table and a hardcoded catalog.
 18→    /// </summary>
 19→    public sealed class ServiceTreeParentResolver : IServiceTreeParentResolver
 20→    {
 21→        private static readonly ParentServiceGroupInfo UnknownParent = new ParentServiceGroupInfo(string.Empty, string.Empty, string.Empty);
 22→
 23→        private readonly IServiceTreeNodeLookup nodeLookup;
 24→        private readonly ILogger<ServiceTreeParentResolver> logger;
 25→        private readonly ConcurrentDictionary<string, ParentServiceGroupInfo> cache =
 26→            new ConcurrentDictionary<string, ParentServiceGroupInfo>(StringComparer.OrdinalIgnoreCase);
 27→
 28→        /// <summary>
 29→        /// Initializes a new instance of the <see cref="ServiceTreeParentResolver"/> class.
 30→        /// </summary>
 31→        /// <param name="nodeLookup">Service Tree node lookup.</param>
 32→        /// <param name="logger">Logger instance.</param>
 33→        public ServiceTreeParentResolver(IServiceTreeNodeLookup nodeLookup, ILogger<ServiceTreeParentResolver> logger)
 34→        {
 35→            this.nodeLookup = nodeLookup ?? throw new ArgumentNullException(nameof(nodeLookup));
 36→            this.logger = logger ?? throw new ArgumentNullException(nameof(logger));
 37→        }
 38→
 39→        /// <inheritdoc/>
 40→        public async Task<IReadOnlyDictionary<string, ParentServiceGroupInfo>> ResolveParentsAsync(
 41→            IEnumerable<string> serviceTreeIds,
 42→            CancellationToken cancellationToken)
 43→        {
 44→            var results = new ConcurrentDictionary<string, ParentServiceGroupInfo>(StringComparer.OrdinalIgnoreCase);
 45→            var uniqueIds = (serviceTreeIds ?? Enumerable.Empty<string>())
 46→                .Where(id => !string.IsNullOrWhiteSpace(id))
 47→                .Select(id => id.Trim())
 48→                .Distinct(StringComparer.OrdinalIgnoreCase)
 49→                .ToList();
 50→
 51→            if (uniqueIds.Count == 0)
 52→            {
 53→                return results;
 54→            }
 55→
 56→            var idsToQuery = new List<string>();
 57→
 58→            foreach (var id in uniqueIds)
 59→            {
 60→                if (this.cache.TryGetValue(id, out var cached))
 61→                {
 62→                    results[id] = cached;
 63→                    continue;
 64→                }
 65→
 66→                if (ServiceTreeParentGroupCatalog.ParentsById.TryGetValue(id, out var directMatch))
 67→                {
 68→                    this.cache[id] = directMatch;
 69→                    results[id] = directMatch;
 70→                    continue;
 71→                }
 72→
 73→                idsToQuery.Add(id);
 74→            }
 75→
 76→            if (idsToQuery.Count > 0)
 77→            {
 78→                // Use the flattened hierarchy table — one query, no traversal needed.
 79→                var hierarchyResults = await this.nodeLookup
 80→                    .GetHierarchyNodesByServiceIdsAsync(idsToQuery, cancellationToken)
 81→                    .ConfigureAwait(false);
 82→
 83→                this.logger.LogInformation(
 84→                    "ServiceTreeParentResolver: Queried {QueryCount} IDs, got {ResultCount} hierarchy results.",
 85→                    idsToQuery.Count,
 86→                    hierarchyResults.Count);
 87→
 88→                foreach (var id in idsToQuery)
 89→                {
 90→                    if (hierarchyResults.TryGetValue(id, out var hierarchyNode))
 91→                    {
 92→                        var parent = this.MatchFromHierarchyNode(hierarchyNode);
 93→                        if (parent != null)
 94→                        {
 95→                            this.logger.LogInformation(
